import{_ as b,o as e,c as a,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"独角犀牛","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/独角犀牛.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/独角犀牛.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/独角犀牛.md"};function o(d,r,l,_,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"独角犀牛",tabindex:"-1"},[t("独角犀牛 "),p("a",{class:"header-anchor",href:"#独角犀牛","aria-label":'Permalink to "独角犀牛"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),n('<h1 id="独角犀牛-1" tabindex="-1">独角犀牛 <a class="header-anchor" href="#独角犀牛-1" aria-label="Permalink to &quot;独角犀牛&quot;">​</a></h1><p>独角犀牛</p><p>D+500<br> 独立随从</p><p>独角犀牛，原名铁甲犀牛，尖尖宝可梦。虽然头脑很差但力气很大，可以用撞击把高楼大厦撞得粉碎。<br> 系别：地面+岩石系</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量6<br> ■敏捷2<br> ■耐力6<br> ▓▓心智属性<br> ■智力2<br> ■感知2<br> ■决心4<br> ▓▓互动属性<br> ■风度4<br> ■操控4<br> ■沉着2</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动3-投掷3-反射3<br> ■求生5-强韧5-动物沟通3<br> ■射击1<br> ■武技5-角5</p><p>▓▓心智系<br> ■学识3-魔法3<br> ■器用1<br> ■手艺1<br> ■专注3-意志3</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 5<br> ▓速度 （力量【6】+敏捷【2】+体积【5】+每1点敏捷上的附加获得3移动速度）=13米<br> ▓先攻 （敏捷【2】+沉着【2】）=4<br> ▓防御 （敏捷感知的平均值【2】+较高者的附加成功【】）= 2<br> ▓生命值 （耐力【6】+体积【5】+耐力附加【1 】×5）=16<br> ▓意志力池 （决心【4】+沉着【2】+决心附加【 】×2）=6<br> ▓意志 （决心【4】+专注3+意志【3】）=10+1<br> ▓反射 （敏捷【2】+运动3+反射【3】）=8+1<br> ▓强韧 （耐力【6】+生存5+强韧【5】）=16+3<br> ▓侦查 （感知【2】+洞察1+侦查【1】）=4<br> ▓敏感范围 （感知【2】*20米+感知上的附加成功【 】*20米）=40米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：<br> 普通攻击预设：力量6+武技5+角5+天生武器伤害3L=19+3</p><p>宝可梦技艺近战攻击预设：力量+武技+角+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御2 天生防御6+1 钝击易伤4 冻寒能量易伤4 雷电能量抗力5/6（当选择特性避雷针时）</p><p>▓▓▓▓性别：公/母（购买时选定其中一种，选定之后无法更改）</p><p>▓▓▓▓特性：</p><p>【岩石系宝可梦】：岩石系宝可梦拥有得天独厚的防御力，但同样对于受过训练的特殊打击而言也更加脆弱。独角犀牛获得6点天生防御以及1点基于天生防御的附加成功，同时具有4点钝击易伤，以及4点冻寒能量易伤。</p><p>【地面系宝可梦】：地面系宝可梦是天生的电系克星，独角犀牛获得了5点雷电能量抗力。</p><p>【尖尖宝可梦】：独角犀牛的角是它在野外环境中赖以生存的根本，是武器也是象征。独角犀牛的角视为3L伤害的天生武器。</p><p>【避雷针】：拥有避雷针特性的宝可梦会将敌人的雷电能量伤害化为己用。独角犀牛获得1点雷电能量抗力，且当独角犀牛承受雷电能量伤害时，可以使其施法检定获得2点的能量加值。</p><p>【坚硬脑袋】：拥有坚硬脑袋特性的宝可梦可以在使用受反作用力伤害的技能时抵消部分伤害。一场战斗开始时，独角犀牛会获得3点临时生命，持续一场景。此特性所获得的所有临时生命仅能用来抵消会对自身造成伤害的宝可梦技能所造成的伤害，例：舍身冲撞。</p><p>【舍身】：拥有舍身特性的宝可梦在使用受反作用力伤害的技能时可以额外提升技能威力。独角犀牛在使用会对自身造成伤害的宝可梦技能时，额外获得3DP技艺加值，以及1点来自技艺的附加成功。</p><p>以上三种特性仅在购买独角犀牛时可以选择其中一种生效，一旦选择便无法更改。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：<br> 岩石系技能：岩石暴击，尖石攻击，岩崩，岩石封锁，落石，岩石打磨，流星光束</p><p>地面系技能：地震，重踏，直冲钻，挖洞，十万马力，大地之力，泥巴射击，热沙大地</p><p>一般系技能：舍身冲撞，剑舞，守住，替身，报恩，硬撑，火箭头槌，泰山压顶</p><p>格斗系技能：双倍奉还，蛮力，真气拳，真气弹，扑击</p><p>火系技能：喷射火焰，大字爆炎，高温重压，火焰拳</p><p>电系技能：打雷，十万伏特，雷电拳</p><p>水系技能：冲浪，水炮，求雨</p><p>冰系技能：冰冻拳，暴风雪，冰冻光束，冰冻之风</p><p>恶系技能：咬碎，投掷，小偷</p><p>幽灵系技能：暗影爪</p><p>超能系技能：睡觉</p><p>钢系技能：铁壁，铁头，加农光炮，重磅冲撞，修长之角</p><p>龙系技能：逆鳞，龙之波动，广域破坏</p><p>虫系技能：超级角击</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>【钻角犀兽】由独角犀牛支付10XP进化而来<br> 独立随从<br> 钻角犀兽视为C级召唤物。<br> 钻角犀兽仅能由独角犀牛进化而来，不可单独购买</p><p>钻角犀兽，钻角犀兽原名铁甲暴龙，钻锥宝可梦，独角犀牛的进化形。可以只用后腿行走，智力也发达了许多，像盔甲一样的皮肤可以抵挡住岩浆。<br> 系别：地面+岩石系</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量11<br> ■敏捷6<br> ■耐力11<br> ▓▓心智属性<br> ■智力6<br> ■感知6<br> ■决心9<br> ▓▓互动属性<br> ■风度9<br> ■操控9<br> ■沉着6</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动5-投掷5-反射5<br> ■求生8-强韧8-动物沟通5<br> ■射击1<br> ■武技8-角8</p><p>▓▓心智系<br> ■学识5-魔法5<br> ■器用1<br> ■手艺1<br> ■专注5-意志5</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 5<br> ▓速度 （力量【11】+敏捷【6】+体积【5】+每1点敏捷上的附加获得3移动速度）=25米<br> ▓先攻 （敏捷【6】+沉着【6】）=12<br> ▓防御 （敏捷感知的平均值【6】+较高者的附加成功【1】）= 6+1<br> ▓生命值 （耐力【11】+体积【5】+耐力附加【2 】×5）=26<br> ▓意志力池 （决心【9】+沉着【6】+决心附加【 1】×2）=17<br> ▓意志 （决心【9】+专注5+意志【5】）=19+3<br> ▓反射 （敏捷【6】+运动5+反射【5】）=16+3<br> ▓强韧 （耐力【11】+生存8+强韧【8】）=27+5<br> ▓侦查 （感知【6】+洞察1+侦查【】）=7+1<br> ▓敏感范围 （感知【6】*20米+感知上的附加成功【 1】*20米）=140米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：<br> 普通攻击预设：力量+武技+角+天生武器伤害=33+5</p><p>宝可梦技艺近战攻击预设：力量+武技+角+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御6+1 天生防御12+1 钝击易伤8 冻寒能量易伤8 雷电能量抗力5/11（在选择避雷针特性时生效）</p><p>▓▓▓▓性别：公/母（购买时选定其中一种，选定之后无法更改）</p><p>▓▓▓▓特性：<br> 【提升：岩石系宝可梦】：进化以后进一步提升了岩石系宝可梦的防御能力，同时也进一步暴露出岩石系宝可梦的弱点。钻角犀兽获得额外6点天生防御以及基于天生防御的【防弹】特性。同时钝击易伤提升至8点，冻寒能量易伤提升至8点。</p><p>【尖尖宝可梦特性进化为钻锥宝可梦特性】：钻角犀兽的角现在可以进行超高速旋转，并通过这种方式来进一步强化角的破坏力。钻角犀兽的角作为天生武器的伤害提升至6L。</p><p>【提升：避雷针】：拥有避雷针特性的宝可梦会将敌人的雷电能量伤害化为己用。此特性获得的雷电能量抗力提升至6。且当其承受雷电能量伤害时，可以使其施法检定获得6点的能量加值。</p><p>【提升：坚硬脑袋】：拥有坚硬脑袋特性的宝可梦可以在使用受反作用力伤害的技能时抵消部分伤害。钻角犀兽获得的临时生命提升至10点，此特性所获得的所有临时生命仅能用来抵消会对自身造成伤害的宝可梦技能所造成的伤害。</p><p>【提升：舍身】：拥有舍身特性的宝可梦在使用受反作用力伤害的技能时可以额外提升技能威力。钻角犀兽在使用会对自身造成伤害的宝可梦技能时额外获得的技艺加值提升至8点，额外获得的来自技艺的附加成功提升至2点。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>同【独角犀牛】。</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>【超甲狂犀】由钻角犀兽支付20XP进化而来/支付C+1000购买道具【护具】后进化而来，护具为消耗品，仅能用于进化钻角犀兽。<br> 独立随从<br> 超甲狂犀视为B级召唤物<br> 超甲狂犀仅能由钻角犀兽进化而来，不可单独购买</p><p>超甲狂犀，钻锥宝可梦，钻角犀兽的进化形，在手掌的洞里塞满岩石，用肌肉的力量发射出去，偶尔会把小拳石也发射出去。</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量16<br> ■敏捷11<br> ■耐力16<br> ▓▓心智属性<br> ■智力11<br> ■感知11<br> ■决心14<br> ▓▓互动属性<br> ■风度14<br> ■操控14<br> ■沉着11</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动11-投掷11-反射8<br> ■求生8-强韧8-动物沟通8<br> ■射击1<br> ■武技11-角11</p><p>▓▓心智系<br> ■学识8-魔法8<br> ■器用1<br> ■手艺1<br> ■专注8-意志8</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 7<br> ▓速度 （力量【16】+敏捷【11】+体积【7】+每1点敏捷上的附加获得3移动速度）=41米<br> ▓先攻 （敏捷【11】+沉着【11】）=22<br> ▓防御 （敏捷感知的平均值【11】+较高者的附加成功【2】）= 11+2<br> ▓生命值 （耐力【16】+体积【7】+耐力附加【 3】×5）=38<br> ▓意志力池 （决心【14】+沉着【11】+决心附加【 2】×2）=29<br> ▓意志 （决心【14】+专注8+意志【8】）=30+5<br> ▓反射 （敏捷【11】+运动11+反射【8】）=30+6<br> ▓强韧 （耐力【16】+生存8+强韧【8】）=32+6<br> ▓侦查 （感知【11】+洞察1+侦查【】）=12+2<br> ▓敏感范围 （感知【11】*20米+感知上的附加成功【 2】*20米）=260米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：<br> 普通攻击预设：力量+武技+角+天生武器伤害=44+7</p><p>宝可梦技艺近战攻击预设：力量+武技+角+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御11+2 天生防御18+3【防弹】【防能量】/22+3【防弹】【防能量】【坚韧】（选择特性坚硬岩石时生效） 钝击易伤8 冻寒能量易伤8 雷电能量抗力5/19（选择特性避雷针时生效）</p><p>▓▓▓▓性别：公/母（购买时选定其中一种，选定之后无法更改）</p><p>▓▓▓▓特性：<br> 【提升：岩石系宝可梦】：最终形态的超甲狂犀拥有顶级的岩石系宝可梦才配得上的防御力，天生防御再提升6点并获得2点基于天生防御的附加成功，以及基于天生防御的【防能量武器】特性。</p><p>【提升：避雷针】：此时的超甲狂犀已经不再会被常见的雷电能量攻击伤害，此特性获得的雷电能量抗力提升至14，且当超甲狂犀受到雷电能量攻击时，可以使其施法检定获得11点的能量加值且额外获得2点来自能量的附加成功。</p><p>【提升：舍身】：拥有舍身特性的宝可梦在使用受反作用力伤害的技能时可以额外提升技能威力。超甲狂犀在使用会对自身造成伤害的宝可梦技能时额外获得的技艺加值提升至13点，额外获得的来自技艺的附加成功提升至5点。</p><p>【坚硬脑袋特性进化为特性：坚硬岩石】：拥有坚硬岩石特性的岩石系宝可梦不仅在本就出色的防御力上精益求精，更是针对自身的弱点进化出了特别的防御措施。超甲狂犀失去前两种形态的特性坚硬脑袋带来的所有好处，而是在战斗开始时，获得10点临时生命，持续一场景，这种临时生命仅对钝击伤害和冻寒能量伤害生效。且超甲狂犀的天生防御再额外获得4点提升，且获得基于天生防御的【坚韧】特性。<br> ▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>同独角犀牛，且超甲狂犀可额外学习专属技能【岩石炮】。</p><p>岩石炮B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 岩石系物理技能，该宝可梦进行一次近战攻击检定，超甲狂犀竖起自己厚重的手掌，将孔洞中的石头以肌肉的力量打出，这次攻击获得60米触及范围提升，获得等同于宝可梦力量值的技艺加值以及1点来自于技艺的附加成功。这次攻击具有15点破甲，若攻击的目标是处于飞行状态的目标，则这次攻击中若有在抵消对方防御中的护甲后溢出的破甲值则可以以1：1的比例转化为高速生效。</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',102)])])}const P=b(s,[["render",o]]);export{f as __pageData,P as default};
